        map.put(number, map.getOrDefault(number, 0) + 1);
    }

    public boolean find(int value) {
        for (int num : map.keySet()) {
            int complement = value - num;
            if (map.containsKey(complement)) {
                if (complement != num || map.get(complement) > 1) {
                    return true;
                }
            }
        }
        return false;
    }
